arguments.typescript:
const { getRepoTask, applyRepoChange } = (globalThis as any).api;
const task = await getRepoTask();
console.log("task:", JSON.stringify(task));
const result = await applyRepoChange({ repo: task.repo, branch: task.defaultBranch });
console.log("result:", JSON.stringify(result));
return {
  repo: result.repo,
  branch: result.branch,
  changedFiles: result.changedFiles,
  prTitle: result.prTitle,
  prBody: result.prBody,
  prUrl: result.prUrl
};

